func (tv *TokenValidator) ValidateToken(token string) (*ServiceIdentity, error) {
	parts := strings.SplitN(token, ".", 3)
	if len(parts) != 3 {
		return nil, fmt.Errorf("invalid token format: expected 3 parts, got %d", len(parts))
	}

	payload := parts[0] + "." + parts[1]
	signature := parts[2]

	// Verify HMAC signature
	mac := hmac.New(sha256.New, tv.secretKey)
	mac.Write([]byte(payload))
	expectedSig := hex.EncodeToString(mac.Sum(nil))

	if !hmac.Equal([]byte(signature), []byte(expectedSig)) {
		return nil, fmt.Errorf("invalid token signature")
	}

	// Parse payload
	fields := strings.Split(parts[0], ":")
	if len(fields) < 3 {
		return nil, fmt.Errorf("invalid token payload")
	}

	serviceName := fields[0]
	namespace := fields[1]
	clusterID := fields[2]

	// Parse permissions
	permissions := strings.Split(parts[1], ",")

	// Check if service is registered
	tv.mu.RLock()
	reg, exists := tv.trustedServices[serviceName]
	tv.mu.RUnlock()

	if !exists {
		return nil, fmt.Errorf("service %q is not registered", serviceName)
	}

	// Verify permissions match registration
	for _, perm := range permissions {
		found := false
		for _, regPerm := range reg.Permissions {
			if perm == regPerm {
				found = true
				break
			}
		}
		if !found {
			return nil, fmt.Errorf("permission %q not authorized for service %q", perm, serviceName)
		}
	}

	return &ServiceIdentity{
		ServiceName: serviceName,
		Namespace:   namespace,
		ClusterID:   clusterID,
		Permissions: permissions,
		ExpiresAt:   time.Now().Add(1 * time.Hour), // tokens valid for 1 hour in this example
	}, nil
}

func (tv *TokenValidator) GenerateToken(serviceName, namespace, clusterID string, permissions []string) string {
	payload := fmt.Sprintf("%s:%s:%s.%s", serviceName, namespace, clusterID, strings.Join(permissions, ","))
	mac := hmac.New(sha256.New, tv.secretKey)
	mac.Write([]byte(payload))
	signature := hex.EncodeToString(mac.Sum(nil))
	return payload + "." + signature
}

