func authenticate(ctx context.Context, validator *TokenValidator) (context.Context, error) {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return nil, status.Error(codes.Unauthenticated, "missing metadata")
	}

	// Extract authorization token
	authTokens := md.Get("authorization")
	if len(authTokens) == 0 {
		return nil, status.Error(codes.Unauthenticated, "missing authorization token")
	}

	token := authTokens[0]
	// Strip "Bearer " prefix if present
	if strings.HasPrefix(token, "Bearer ") {
		token = strings.TrimPrefix(token, "Bearer ")
	}

	// Extract additional mesh metadata
	sourceService := ""
	if vals := md.Get("x-mesh-source-service"); len(vals) > 0 {
		sourceService = vals[0]
	}

	requestID := ""
	if vals := md.Get("x-request-id"); len(vals) > 0 {
		requestID = vals[0]
	}

	traceID := ""
	if vals := md.Get("x-trace-id"); len(vals) > 0 {
		traceID = vals[0]
	}

	// Validate the token
	identity, err := validator.ValidateToken(token)
	if err != nil {
		return nil, status.Errorf(codes.Unauthenticated, "invalid token: %v", err)
	}

	// Cross-check source service header with token identity
	if sourceService != "" && sourceService != identity.ServiceName {
		return nil, status.Errorf(codes.Unauthenticated,
			"source service mismatch: header=%s token=%s", sourceService, identity.ServiceName)
	}

	if requestID != "" {
		log.Printf("Request ID: %s, Trace ID: %s", requestID, traceID)
	}

	// Store identity in context
	newCtx := context.WithValue(ctx, serviceIdentityKey, identity)
	return newCtx, nil
}

