// ---- Rate limiting middleware ----

type RateLimiter struct {
	mu       sync.Mutex
	requests map[string][]time.Time
	limit    int
	window   time.Duration
}

func NewRateLimiter(limit int, window time.Duration) *RateLimiter {
	return &RateLimiter{
		requests: make(map[string][]time.Time),
		limit:    limit,
		window:   window,
	}
}

func (rl *RateLimiter) Allow(serviceID string) bool {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	now := time.Now()
	cutoff := now.Add(-rl.window)

	// Clean old entries
	if times, ok := rl.requests[serviceID]; ok {
		var valid []time.Time
		for _, t := range times {
			if t.After(cutoff) {
				valid = append(valid, t)
			}
		}
		rl.requests[serviceID] = valid
	}

	if len(rl.requests[serviceID]) >= rl.limit {
		return false
	}

	rl.requests[serviceID] = append(rl.requests[serviceID], now)
	return true
}

func RateLimitInterceptor(limiter *RateLimiter) grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		identity, ok := ServiceIdentityFromContext(ctx)
		if ok {
			if !limiter.Allow(identity.ServiceName) {
				return nil, status.Errorf(codes.ResourceExhausted,
					"rate limit exceeded for service %q", identity.ServiceName)
			}
		}
		return handler(ctx, req)
	}
}

// ---- Chain interceptors ----

func ChainUnaryInterceptors(interceptors ...grpc.UnaryServerInterceptor) grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		chain := handler
		for i := len(interceptors) - 1; i >= 0; i-- {
			interceptor := interceptors[i]
			next := chain
			chain = func(ctx context.Context, req interface{}) (interface{}, error) {
				return interceptor(ctx, req, info, next)
			}
		}
		return chain(ctx, req)
	}
}

// ---- Logging interceptor ----

func LoggingInterceptor() grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		start := time.Now()
		resp, err := handler(ctx, req)
		duration := time.Since(start)

		statusCode := codes.OK
		if err != nil {
			if st, ok := status.FromError(err); ok {
				statusCode = st.Code()
			}
		}

		identity, _ := ServiceIdentityFromContext(ctx)
		serviceName := "unknown"
		if identity != nil {
			serviceName = identity.ServiceName
		}

		log.Printf("gRPC call: method=%s service=%s status=%s duration=%v",
			info.FullMethod, serviceName, statusCode, duration)

		return resp, err
	}
}

